function FloatingEventStream() {
  const [events, setEvents] = useState([]);

  useEffect(() => {
    // WebSocket connection
    const ws = new WebSocket('wss://ada-hub.local/hq/events');

    ws.onmessage = (msg) => {
      const event = JSON.parse(msg.data);
      setEvents(prev => [event, ...prev].slice(0, 50));
    };

    return () => ws.close();
  }, []);

  return (
    <motion.div
      className="floating-event-stream"
      style={{
        position: 'fixed',
        left: 20,
        top: 120,
        width: 400,
        height: 'calc(100vh - 200px)',
        background: 'rgba(0, 10, 20, 0.8)',
        backdropFilter: 'blur(20px)',
        border: '1px solid rgba(0, 255, 255, 0.2)',
        borderRadius: 20,
        overflow: 'hidden',
      }}
    >
      {/* Header */}
