function EventBubble({ event, index }) {
  const urgencyColors = {
    normal: 'rgba(0, 200, 255, 0.2)',
    high: 'rgba(255, 170, 0, 0.3)',
    emergency: 'rgba(255, 0, 0, 0.4)',
  };

  const urgencyGlow = {
    normal: '0 0 10px rgba(0, 200, 255, 0.5)',
    high: '0 0 20px rgba(255, 170, 0, 0.7)',
    emergency: '0 0 30px rgba(255, 0, 0, 0.9)',
  };

  return (
    <motion.div
      initial={{ x: -500, opacity: 0, scale: 0.8 }}
      animate={{ x: 0, opacity: 1, scale: 1 }}
      exit={{ x: 500, opacity: 0, scale: 0.8 }}
      transition={{ 
        type: 'spring',
        damping: 20,
        stiffness: 300,
        delay: index * 0.05
      }}
      whileHover={{ scale: 1.05, x: 10 }}
      style={{
        background: urgencyColors[event.urgency],
        backdropFilter: 'blur(10px)',
        border: `1px solid ${getTenantColor(event.tenant)}`,
        borderRadius: 12,
        padding: 12,
        boxShadow: urgencyGlow[event.urgency],
        cursor: 'pointer',
      }}
      className="event-bubble"
    >
      <div className="flex items-start gap-3">
        {/* Tenant Icon */}
        <div 
          className="tenant-icon-mini"
          style={{
            width: 32,
            height: 32,
            borderRadius: 8,
            background: getTenantColor(event.tenant),
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            fontSize: 16,
          }}
        >
          {getTenantIcon(event.tenant)}
        </div>

        {/* Event Content */}
        <div className="flex-1">
          <div className="flex items-center justify-between mb-1">
            <span className="text-cyan-300 text-xs font-bold">
              {event.tenant}
            </span>
            <span className="text-gray-400 text-xs">
              {formatTime(event.timestamp)}
            </span>
          </div>

          <div className="text-white text-sm">
            {event.type}: {event.data.message}
          </div>

          {/* Related Tenants */}
          {event.related_tenants && (
            <div className="flex items-center gap-1 mt-2">
              <span className="text-gray-400 text-xs">→</span>
              {event.related_tenants.map(tenant => (
                <span 
                  key={tenant}
                  className="text-xs px-2 py-1 rounded"
                  style={{
                    background: getTenantColor(tenant),
                    opacity: 0.7,
                  }}
                >
                  {getTenantIcon(tenant)}
                </span>
              ))}
            </div>
          )}
        </div>
      </div>
    </motion.div>
  );
}
