        opacity: 0 
      }}
      animate={{ x: 0, opacity: 1 }}
      exit={{ opacity: 0, scale: 0.8 }}
      transition={{ type: 'spring', damping: 25 }}
      className={`vhf-message ${isIncoming ? 'incoming' : 'outgoing'}`}
      style={{
        display: 'flex',
        flexDirection: 'column',
        alignItems: isIncoming ? 'flex-start' : 'flex-end',
      }}
    >
