          {formatTime(message.timestamp)}
        </span>
      </div>

      {/* Message Bubble */}
      <motion.div
        className="message-bubble"
        style={{
          background: isIncoming 
            ? 'linear-gradient(135deg, rgba(0, 255, 136, 0.2), rgba(0, 200, 100, 0.2))'
            : 'linear-gradient(135deg, rgba(0, 150, 255, 0.2), rgba(0, 100, 200, 0.2))',
          border: `1px solid ${isIncoming ? '#00ff88' : '#0096ff'}`,
          borderRadius: 12,
          padding: '12px 16px',
          maxWidth: '80%',
          boxShadow: `0 0 20px ${isIncoming ? 'rgba(0, 255, 136, 0.3)' : 'rgba(0, 150, 255, 0.3)'}`,
        }}
        whileHover={{ scale: 1.02 }}
      >
        <p className="text-white text-sm leading-relaxed">
          {message.text}
        </p>

        {/* Audio Waveform Animation (for authenticity) */}
        {message.isPlaying && (
          <div className="flex items-center gap-1 mt-2">
            {[...Array(20)].map((_, i) => (
              <motion.div
                key={i}
                className="bg-green-400"
                style={{ width: 2, borderRadius: 2 }}
                animate={{
                  height: [4, Math.random() * 20 + 4, 4],
                }}
                transition={{
                  duration: 0.5,
                  repeat: Infinity,
                  delay: i * 0.05,
                }}
              />
            ))}
          </div>
        )}
      </motion.div>
    </motion.div>
  );
}

function SignalStrengthIndicator({ strength }) {
  return (
    <div className="flex items-end gap-1">
      {[...Array(5)].map((_, i) => (
        <motion.div
          key={i}
          className={`w-2 rounded-sm ${
            i < strength ? 'bg-green-400' : 'bg-gray-600'
          }`}
          style={{ height: (i + 1) * 4 }}
          animate={i < strength ? { opacity: [0.5, 1, 0.5] } : {}}
          transition={{ duration: 1, repeat: Infinity, delay: i * 0.1 }}
        />
      ))}
    </div>
  );
}
