function AmbientAudioController() {
  const audioContext = new AudioContext();

  const playEventSound = (eventType) => {
    const sounds = {
      'vhf_incoming': '/sounds/radio_beep.mp3',
      'berth_assigned': '/sounds/success_chime.mp3',
      'emergency': '/sounds/alert.mp3',
      'revenue': '/sounds/cash_register.mp3',
    };

    const audio = new Audio(sounds[eventType]);
    audio.volume = 0.3;
    audio.play();
  };

  // Ambient marina sounds
  useEffect(() => {
    const ambient = new Audio('/sounds/marina_ambient.mp3');
    ambient.loop = true;
    ambient.volume = 0.1;
    ambient.play();

    return () => ambient.pause();
  }, []);

  return null;
}
